using System.ComponentModel.DataAnnotations;

namespace sv_86f58084a5eb4932a599c0ed6ecff5f2.Models;

public class PersonalInfoModel
{
    [Required(ErrorMessage = "Full name is required.")]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone number is required.")]
    [Phone(ErrorMessage = "Invalid phone number.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Address is required.")]
    public string Address { get; set; } = string.Empty;
}

public class WorkEntryModel
{
    [Required(ErrorMessage = "Company name is required.")]
    public string Company { get; set; } = string.Empty;

    [Required(ErrorMessage = "Job title is required.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Start date is required.")]
    public DateTime? StartDate { get; set; }

    public DateTime? EndDate { get; set; }

    public bool IsCurrentPosition { get; set; }

    public string Description { get; set; } = string.Empty;
}

public class ReferenceModel
{
    [Required(ErrorMessage = "Name is required.")]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Relationship is required.")]
    public string Relationship { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone is required.")]
    [Phone(ErrorMessage = "Invalid phone number.")]
    public string Phone { get; set; } = string.Empty;
}

@using sv_86f58084a5eb4932a599c0ed6ecff5f2.Models

<div class="step-indicator">
    @for (int i = 0; i < Steps.Count; i++)
    {
        var stepIndex = i;
        var stepClass = GetStepClass(stepIndex);
        <div class="step-item @stepClass" @onclick="() => OnStepClick(stepIndex)">
            <div class="step-circle">
                @if (CompletedSteps.Contains(stepIndex))
                {
                    <span class="step-check">&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <div class="step-label">@Steps[stepIndex]</div>
        </div>
        @if (stepIndex < Steps.Count - 1)
        {
            <div class="step-connector @(CompletedSteps.Contains(stepIndex) ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter, EditorRequired]
    public EventCallback<int> OnStepSelected { get; set; }

    private List<string> Steps { get; } = new()
    {
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    };

    private string GetStepClass(int index)
    {
        if (index == CurrentStep) return "active";
        if (CompletedSteps.Contains(index)) return "completed";
        return "future";
    }

    private async Task OnStepClick(int index)
    {
        if (CompletedSteps.Contains(index))
        {
            await OnStepSelected.InvokeAsync(index);
        }
    }
}

