@using sv_86f58084a5eb4932a599c0ed6ecff5f2.Models

<div class="step-indicator">
    @for (int i = 0; i < Steps.Count; i++)
    {
        var stepIndex = i;
        var stepClass = GetStepClass(stepIndex);
        <div class="step-item @stepClass" @onclick="() => OnStepClick(stepIndex)">
            <div class="step-circle">
                @if (CompletedSteps.Contains(stepIndex))
                {
                    <span class="step-check">&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <div class="step-label">@Steps[stepIndex]</div>
        </div>
        @if (stepIndex < Steps.Count - 1)
        {
            <div class="step-connector @(CompletedSteps.Contains(stepIndex) ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public HashSet<int> CompletedSteps { get; set; } = new();

    [Parameter, EditorRequired]
    public EventCallback<int> OnStepSelected { get; set; }

    private List<string> Steps { get; } = new()
    {
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    };

    private string GetStepClass(int index)
    {
        if (index == CurrentStep) return "active";
        if (CompletedSteps.Contains(index)) return "completed";
        return "future";
    }

    private async Task OnStepClick(int index)
    {
        if (CompletedSteps.Contains(index))
        {
            await OnStepSelected.InvokeAsync(index);
        }
    }
}

