@using sv_86f58084a5eb4932a599c0ed6ecff5f2.Models

<div class="step-content">
    <h4>Personal Information</h4>
    <EditForm Model="Model" OnValidSubmit="HandleNext">
        <DataAnnotationsValidator />
        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Full Name *</label>
                <InputText class="form-control" @bind-Value="Model.FullName" />
                <ValidationMessage For="() => Model.FullName" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email *</label>
                <InputText class="form-control" @bind-Value="Model.Email" />
                <ValidationMessage For="() => Model.Email" />
                @if (!string.IsNullOrEmpty(emailError))
                {
                    <div class="text-danger mt-1">@emailError</div>
                }
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone *</label>
                <InputText class="form-control" @bind-Value="Model.Phone" />
                <ValidationMessage For="() => Model.Phone" />
            </div>
            <div class="col-12">
                <label class="form-label">Address *</label>
                <InputText class="form-control" @bind-Value="Model.Address" />
                <ValidationMessage For="() => Model.Address" />
            </div>
        </div>
        <div class="mt-4 d-flex justify-content-end">
            <button type="submit" class="btn btn-primary" disabled="@isValidating">
                @if (isValidating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <span>Validating...</span>
                }
                else
                {
                    <span>Next &rarr;</span>
                }
            </button>
        </div>
    </EditForm>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        emailError = null;
        isValidating = true;

        try
        {
            var isValid = await ValidateEmail(Model.Email);
            if (!isValid)
            {
                emailError = "This email address could not be verified.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@using sv_86f58084a5eb4932a599c0ed6ecff5f2.Models

<div class="step-content">
    <h4>Work History</h4>

    @if (!string.IsNullOrEmpty(validationError))
    {
        <div class="alert alert-danger">@validationError</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="d-flex justify-content-between">
        <button type="button" class="btn btn-secondary" @onclick="OnBack">&larr; Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next &rarr;</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<WorkEntryModel> Entries { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate == null)
            {
                validationError = "Please fill in the company name, job title, and start date for all positions.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_86f58084a5eb4932a599c0ed6ecff5f2.Models

<div class="step-content">
    <h4>References</h4>
    <p class="text-muted">Please provide 2–3 professional references.</p>

    @if (!string.IsNullOrEmpty(validationError))
    {
        <div class="alert alert-danger">@validationError</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="index"
                       ShowRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="d-flex justify-content-between">
        <button type="button" class="btn btn-secondary" @onclick="OnBack">&larr; Back</button>
        <button type="button" class="btn btn-primary" @onclick="HandleNext">Next &rarr;</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                validationError = "Please fill in all fields for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_86f58084a5eb4932a599c0ed6ecff5f2.Models

<div class="step-content">
    <h4>Review & Submit</h4>
    <p class="text-muted">Please review your application before submitting.</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    @if (isSubmitted)
    {
        <div class="alert alert-success">
            <h5>Application Submitted Successfully!</h5>
            <p>Your application ID is: <strong>@applicationId</strong></p>
            <p>Thank you for applying. We will review your application and get back to you.</p>
        </div>
    }
    else
    {
        <!-- Personal Info Section -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Personal Information</strong>
                <a href="#" @onclick="() => OnEditSection.InvokeAsync(0)" @onclick:preventDefault>Edit</a>
            </div>
            <div class="card-body">
                <dl class="row mb-0">
                    <dt class="col-sm-3">Full Name</dt>
                    <dd class="col-sm-9">@PersonalInfo.FullName</dd>
                    <dt class="col-sm-3">Email</dt>
                    <dd class="col-sm-9">@PersonalInfo.Email</dd>
                    <dt class="col-sm-3">Phone</dt>
                    <dd class="col-sm-9">@PersonalInfo.Phone</dd>
                    <dt class="col-sm-3">Address</dt>
                    <dd class="col-sm-9">@PersonalInfo.Address</dd>
                </dl>
            </div>
        </div>

        <!-- Work History Section -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Work History</strong>
                <a href="#" @onclick="() => OnEditSection.InvokeAsync(1)" @onclick:preventDefault>Edit</a>
            </div>
            <div class="card-body">
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-3 pb-3 border-bottom last-no-border">
                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                        <small class="text-muted">
                            @entry.StartDate?.ToString("MMM yyyy") &ndash;
                            @(entry.IsCurrentPosition ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                        </small>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mt-1 mb-0">@entry.Description</p>
                        }
                    </div>
                }
            </div>
        </div>

        <!-- References Section -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>References</strong>
                <a href="#" @onclick="() => OnEditSection.InvokeAsync(2)" @onclick:preventDefault>Edit</a>
            </div>
            <div class="card-body">
                @foreach (var r in References)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <small>@r.Email | @r.Phone</small>
                    </div>
                }
            </div>
        </div>

        <!-- Cover Letter Section -->
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Cover Letter</strong>
                <a href="#" @onclick="() => OnEditSection.InvokeAsync(3)" @onclick:preventDefault>Edit</a>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@CoverLetter</p>
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button type="button" class="btn btn-secondary" @onclick="OnBack">&larr; Back</button>
            <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
                @if (isSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <span>Submitting...</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel PersonalInfo { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<WorkEntryModel> WorkEntries { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<ReferenceModel> References { get; set; } = default!;

    [Parameter, EditorRequired]
    public string CoverLetter { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnEditSection { get; set; }

    [Parameter, EditorRequired]
    public Func<Task<int>> SubmitApplication { get; set; } = default!;

    private bool isSubmitting;
    private bool isSubmitted;
    private int applicationId;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            applicationId = await SubmitApplication();
            isSubmitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"An error occurred while submitting: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

