@page "/apply"
@using sv_86f58084a5eb4932a599c0ed6ecff5f2.Models
@using sv_86f58084a5eb4932a599c0ed6ecff5f2.Services
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepSelected="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo"
                                  OnNext="NextStep"
                                  ValidateEmail="ApplicationService.ValidateEmailAsync" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="references"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep @bind-CoverLetter="coverLetter"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep PersonalInfo="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            OnBack="PreviousStep"
                            OnEditSection="GoToStep"
                            SubmitApplication="SubmitAsync" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = string.Empty;

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task<int> SubmitAsync()
    {
        var application = new JobApplication(
            new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
            new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company,
                e.Title,
                e.StartDate ?? DateTime.MinValue,
                e.IsCurrentPosition ? null : e.EndDate,
                e.Description
            )).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    flex-wrap: wrap;
    padding: 1rem 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.25rem;
    cursor: default;
    min-width: 80px;
}

.step-item.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.875rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s ease;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-item.future .step-circle {
    opacity: 0.5;
}

.step-check {
    font-size: 1rem;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    color: #6c757d;
    max-width: 90px;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.future .step-label {
    opacity: 0.5;
}

.step-connector {
    width: 40px;
    height: 2px;
    background: #dee2e6;
    margin: 0 0.25rem;
    margin-bottom: 1.25rem;
    transition: background 0.2s ease;
}

.step-connector.completed {
    background: #198754;
}

.step-content {
    max-width: 800px;
}

