using sv_86f58084a5eb4932a599c0ed6ecff5f2.Models;

namespace sv_86f58084a5eb4932a599c0ed6ecff5f2.Services;

/// <summary>
/// Default implementation of IApplicationService for development/demo purposes.
/// Replace with a real implementation that calls your backend API.
/// </summary>
public class DefaultApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        // Simulate network delay
        await Task.Delay(1500);
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        // Simulate async validation
        await Task.Delay(500);
        return !string.IsNullOrWhiteSpace(email) && email.Contains('@');
    }
}

